VALUES
  ('pukao-7c4986e7-moex-00227', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-111-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年1月1日分別以$1,200,000購入乙公司普通股及丙公司公司債，皆分類為「透過 其他綜合損益按公允價值衡量之金融資產」，X1年底該乙公司普通股及丙公司公司債之公允價值 分別為$1,150,000及$1,300,000。甲公司於X2年7月1日以$1,100,000將乙公司普通股全數出售， 並於X2年9月30日以$1,400,000出售全部丙公司公司債。已知此交易之本期淨利為$8,000,000、 本期其他綜合損益為$500,000，請問甲公司X2年度考量前述交易後之「本期淨利」及「本期綜合 損益」分別為多少？（不考慮所得稅、利息收入與股利收入）', '["$8,000,000；$550,000", "$7,900,000；$650,000", "$8,200,000；$350,000", "$8,100,000；$450,000"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "415", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00228', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-111-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司X6年12月份銀行對帳單餘額$405,606，12月底在途存款$25,000及未兌現支票$45,000， 其中有$20,000遲至X7年1月底均未兌現。X7年1月份銀行對帳單餘額$580,000，1月底在途存 款$43,000及未兌現支票$52,000。甲公司X7年1月31日現金正確餘額為：', '["$591,000", "$571,000", "$416,606", "$396,606"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "415", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00229', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-111-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司三年來之帳列淨利及淨損分別如下：X1年度淨利$101,000；X2年度淨損$25,600；X3年度', '["公司對存貨採實地盤存 制，各年期末存貨錯誤如下：X1年高估$25,500；X2年低估$8,680；X3年高估$5,540", "公司 購入文具用品，均於購入年度當年以費用列帳，期末未耗用部分，移至次年度繼續使用，但未調 整。未耗用情形如下：X1 年底全部耗盡。X2 年底未耗用部分計有$23,000。X3 年底未耗用部分 有$5,657。甲公司X3年之正確淨利為何？（不考慮所得稅）", "$8,437", "$17,117"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "415", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00230', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-111-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '物價不斷上漲時，定期盤存制之先進先出法和加權平均法，何者銷貨毛利率較高？何者期末存貨 成本較高？', '["先進先出法，先進先出法", "加權平均法，加權平均法", "先進先出法，加權平均法", "加權平均法，先進先出法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "415", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00231', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-111-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年初購買機器設備$500,000，採成本模式衡量並以直線法提列折舊。甲公司X3年底 提列折舊後進行減損測試，可回收金額為$340,000，認列減損損失$25,000。甲公司對耐用年限與 殘值之估計最有可能的組合為下列何者？', '["10年；$25,000", "10年；$50,000", "20年；$25,000", "20年；$50,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "415", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00232', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-111-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司持有乙公司股票並分類為透過損益按公允價值衡量之股票投資，若乙公司發放股票股利， 則甲公司之會計處理何者正確？', '["貸記股利收入", "貸記其他綜合損益", "貸記透過損益按公允價值衡量之股票投資", "無須作會計分錄，僅作備忘記錄 | 41630"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "415", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00233', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-111-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '不動產、廠房及設備於認列後之衡量模式有成本模式與重估價模式，下列敘述何者正確？', '["企業可針對不同類別中之全部不動產、廠房及設備採取不同的衡量模式", "重估價需在每一個會計年度結束日定期執行", "企業應選定每年的同一日進行所有各類資產的重估價", "重估增值或減值皆列於綜合損益表之其他綜合損益項下，並累計至權益項下之重估增值 8甲公司於X1年1月1日以平價買入乙公司發行之面額$100,000、5年期、每年年底付息的債券。 該債券在X1年年底之公允價值為$96,000。該筆債券投資可能被分類為「按攤銷後成本衡量之債 券投資」、「透過損益按公允價值衡量之債券投資」與「透過其他綜合損益按公允價值衡量之債 券投資」。下列有關該債券投資之敘述，何者正確？"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "415", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00234', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-111-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年7月初以$250,000購入機器設備，估計耐用年限5年，無殘值，採成本模式後續 衡量並按直線法提列折舊。X2年底由於環境改變導致有重大跡象顯示該機器之價值已經減損，該 公司於X2年底作減損測試，估計該資產之使用價值為$148,000，公允價值減處分成本為$164,000。 X3 年初經公司重新評估後，估計耐用年限尚有 4 年，殘值不變，折舊方法改為年數合計法，則 X3年應認列之折舊為：', '["$38,500", "$41,000", "$50,000", "$65,600"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "415", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00235', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-111-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '下列敘述，何者不屬於投資性不動產之項目？', '["為獲取長期資本增值，非供正常營業出售所持有之土地", "尚未決定未來用途所持有之土地", "企業擁有並以營業租賃出租之建築物", "持有供員工住宿用之建築物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "415", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00236', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-111-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年初購買設備$10,000,000，估計耐用年限8年、無殘值，採成本模式並以直線法提 列折舊。依照當地法規於 X8 年底除列該設備時須復原附近環境，該公司估計復原成本為 $2,000,000，折現至X1年初則為$933,015（折現率10%）。X1年度該公司需認列與此設備相關之 費用金額為何？（四捨五入至整數位）', '["$1,250,000", "$1,343,302", "$1,459,929", "$1,500,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "415", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL)
